// Script Continued Below

/****   Instructions  START *****   
   Example to change unclassMWM to unclass - call the function with these values 
   updateClassification("unclassMWM", "unclass");

   Add as many calls to the fuction updateClassification as you need to change all of the classification values
****   Instructions  END ******/

// Example - updateClassification("unclassMWM", "unclass");
updateClassification("", "");


function updateClassification(previousClassificationValue, newClassificationValue) {
	updateTableClassification('x_153465_discovert_route_task_instance', "classification", previousClassificationValue, newClassificationValue);
	updateTableClassification('x_153465_discovert_discover_routing_template', "classification", previousClassificationValue, newClassificationValue);
	updateTableClassification('x_153465_discovert_discover_routing_runtime', "classification", previousClassificationValue, newClassificationValue);
	updateTableClassification('x_153465_discovert_route_tasks', "classification", previousClassificationValue, newClassificationValue);
}

function updateTableClassification(table, field, previousClassificationValue, newClassificationValue){
	var grConfidential = new GlideRecord(table);
	grConfidential.addQuery(field, previousClassificationValue);
	grConfidential.query();

	while(grConfidential.next()) {
		grConfidential.setValue(field, newClassificationValue);
		var updateMsg = "Classification Updated in Fix Script: 2.7.404 - Classification Value update; Table: " + table + "; Field: " + field + " by user: " + gs.getUserDisplayName();
		grConfidential.update(updateMsg);
		gs.info(updateMsg);
	}

}
